SELECT COUNT(*)
FROM person
WHERE id_card = #{idCard}

SELECT
FROM person
AND LOWER(name) LIKE LOWER(CONCAT('%', #{name}, '%'))
AND id_card LIKE CONCAT('%', #{idCard}, '%')
AND status = #{status}
ORDER BY person_id DESC LIMIT #{limit} OFFSET #{offset}

